import {Link, useNavigate} from "react-router-dom";
import {useState} from "react";
import axios from "axios";
import {useSelector} from "react-redux";

const LoginForm = () => {
    const [formData, setFormData] = useState({
        username: '',
        email: '',
        password: '',
        confirmPassword: ''
    })
    const [error, setError] = useState('')
    let navigate = useNavigate();
    const {isLoggedIn} = useSelector(state)
    const handleChange = (e) => {
        setFormData({
            ...formData,
            [e.target.name]: e.target.value
        });
    }
    const handleSubmit = async (e) => {
        e.preventDefault();
        try {
            const response = await axios.post('http://localhost:8080/api/auth/signin', {
                email: formData.email,
                password: formData.password
            })
            console.log('Dữ liệu trả về từ backend login: ', response.data);
            if (response.status === 200) {
                localStorage.setItem('isLoggedIn', 'true');
                navigate('/');
            } else {
                setError("Đăng nhập thất bại!.")
            }
        } catch (error) {
            setError("Có lỗi xảy ra, vui lòng thử lại.")
        }
    }
    return (
        <div className="container bg-dark p-5">
            <span> <Link to="/" className="text-decoration-none">Trang chủ </Link>
                <i className="bi bi-chevron-double-right"></i>
                <span className="text-warning"> Đăng nhập</span>
            </span>
            <form onSubmit={handleSubmit} className="container p-4">
                <h2 className="text-warning text-center">Đăng nhập</h2>
                <div className="mb-3 mt-3">
                    <label htmlFor="email">Email:</label>
                    <input
                        type="email"
                        className="form-control"
                        id="email"
                        placeholder="Enter email"
                        name="email"
                        onChange={handleChange}
                        value={formData.email}
                        required/>
                </div>
                <div className="mb-3">
                    <label htmlFor="pwd">Mật khẩu:</label>
                    <input
                        type="password"
                        className="form-control"
                        id="pwd"
                        placeholder="Enter password"
                        name="password"
                        value={formData.password}
                        onChange={handleChange}
                        required/>
                </div>
                <div className="form-check mb-3 text-end">
                    <label className="form-check-label me-3">
                        <Link className="text-decoration-none text-warning" to="/repassword">Quên mật khẩu </Link>
                    </label>
                    <label className="form-check-label">
                        <Link className="text-decoration-none text-warning" to="/register"> Đăng ký</Link>
                    </label>
                </div>
                <button type="submit" className="btn btn-outline-warning form-control mb-3">Đăng nhập</button>
                <button type="submit" className="btn btn-outline-danger form-control">Đăng nhập bằng tài khoản google
                </button>
            </form>
        </div>
    )
}

export default LoginForm;
